INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Multiple Storage Classes$q$, $q$Standard, Nearline, Coldline and Archive classes let teams match cost to access frequency without changing application code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Autoclass$q$, $q$Automatically transitions objects between storage classes based on real access patterns, removing the need for manual lifecycle rules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Object Lifecycle Management$q$, $q$Rules-based automation to transition or delete objects on a schedule, useful for compliance retention and cost control.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Fine-Grained IAM and ACLs$q$, $q$Granular Identity and Access Management permissions at the project, bucket and object level, alongside legacy access control lists.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Object Versioning$q$, $q$Keeps prior versions of objects to protect against accidental overwrites or deletions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Multi-Region and Dual-Region Placement$q$, $q$Bucket location options for latency optimization, redundancy and data residency compliance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Native Google Cloud Integration$q$, $q$Direct integration with BigQuery, Dataflow, Vertex AI and Cloud Functions for analytics and machine learning workloads.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Encryption and Signed URLs$q$, $q$Default server-side encryption plus customer-managed and customer-supplied key options, and signed URLs for time-limited access.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Seamless integration with BigQuery, Vertex AI and other Google Cloud services for analytics and machine learning.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Autoclass automatically optimizes storage costs without manual tiering rules.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Consistent global namespace and unified API across all storage classes.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Strong durability and availability backed by Google's global infrastructure.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Network egress pricing can be higher than some competitors at large scale.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Smaller third-party tooling and consulting ecosystem compared to Amazon S3.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Nearline, Coldline and Archive classes carry minimum storage durations and retrieval fees that require careful planning.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Steeper learning curve for teams not already using Google Cloud Platform.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$What is Google Cloud Storage used for?$q$, $q$Google Cloud Storage is used to store and serve unstructured data such as backups, media files, website assets, logs and machine learning datasets at any scale.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$How much does Google Cloud Storage cost?$q$, $q$Pricing is usage-based, starting around $0.020 per GB per month for Standard Storage, with cheaper Nearline, Coldline and Archive classes for less frequently accessed data, plus separate operation and egress charges. A free tier offers 5GB per month in select US regions.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$What is the difference between Standard, Nearline, Coldline and Archive storage?$q$, $q$The classes differ in expected access frequency, minimum storage duration and retrieval fees, from Standard for frequently accessed hot data to Archive for data accessed less than once a year.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Does Google Cloud Storage have a free tier?$q$, $q$Yes, the Always Free tier includes 5GB of Standard Storage per month in specific US regions, along with limited free operations and network egress.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$How does Google Cloud Storage compare to Amazon S3?$q$, $q$Both offer comparable durability and core object storage capability. GCS differentiates with Autoclass automatic tiering and tighter integration with Google's data and AI stack, while S3 has a larger third-party ecosystem.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Is Google Cloud Storage secure and compliant?$q$, $q$Yes, it includes default encryption at rest and in transit, customer-managed encryption key options, fine-grained IAM controls, and supports major compliance frameworks used by regulated enterprises.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Data Lake and Analytics Backing Store$q$, $q$Organizations use GCS as the storage layer for data lakes queried directly by BigQuery and processed with Dataflow or Vertex AI pipelines.$q$, $q$Data engineers and analytics teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Website and Media Hosting$q$, $q$Developers and small businesses host static websites, images and video assets on GCS, often paired with Cloud CDN for fast global delivery.$q$, $q$Developers and small businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Backup and Disaster Recovery Archiving$q$, $q$Enterprises use Nearline, Coldline and Archive classes to store backup copies and compliance records at low cost with defined retrieval expectations.$q$, $q$IT and enterprise operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Always Free Tier$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["5GB of Standard Storage per month in select US regions","5,000 Class A operations per month","50,000 Class B operations per month","1GB of network egress to most destinations per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Standard Storage$q$, $q$From $0.020 per GB per month$q$, $q$Usage-based$q$, NULL, $q$["Lowest latency, highest availability tier","No minimum storage duration","Best for frequently accessed, hot data","Available in region, dual-region and multi-region placements"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Nearline Storage$q$, $q$From $0.010 per GB per month$q$, $q$Usage-based$q$, NULL, $q$["Best for data accessed less than once a month","30-day minimum storage duration","Retrieval fee applies","Same API and durability as Standard Storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Coldline Storage$q$, $q$From $0.004 per GB per month$q$, $q$Usage-based$q$, NULL, $q$["Best for data accessed roughly once a quarter","90-day minimum storage duration","Higher retrieval fee than Nearline","Ideal for backup copies"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$Archive Storage$q$, $q$From $0.0012 per GB per month$q$, $q$Usage-based$q$, NULL, $q$["Lowest-cost class for long-term retention","365-day minimum storage duration","Highest retrieval fee and latency","Suited to compliance and disaster-recovery archives"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Cloud Storage is Google's object storage platform, launched in May 2010 as part of Google Cloud Platform. It stores unstructured data such as backups, media files, logs and datasets in globally namespaced buckets, accessible through a unified API, web console and command-line tools.$q$, $q$It competes directly with Amazon S3 and Azure Blob Storage and is a foundational component for data lakes, website hosting, backup and disaster recovery, and machine learning pipelines built on Google Cloud.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GCS organizes data into four storage classes, Standard, Nearline, Coldline and Archive, that share the same API and durability but differ in access frequency, minimum storage duration and retrieval cost. Autoclass automatically moves objects between classes based on real access patterns.$q$, $q$Additional capabilities include Object Versioning, Object Lifecycle Management, fine-grained IAM permissions, customer-managed encryption keys, signed URLs, and native integration with BigQuery, Dataflow, Vertex AI and Cloud Functions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GCS pricing is usage-based, billed per GB per month for storage plus separate charges for operations, retrieval and network egress. Standard Storage starts around $0.020 per GB per month, with Nearline, Coldline and Archive priced progressively lower but carrying minimum storage durations and retrieval fees.$q$, $q$An Always Free tier includes 5GB of Standard Storage per month in select US regions plus limited free operations and egress, making it accessible for small projects and evaluation before committing to paid usage.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2d8614e8-6ffd-43b6-a2a4-26fe4217c0bd', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Real-Time Collaborative Editing$q$, $q$Multiple users can simultaneously edit the same Docs, Sheets or Slides file with live cursors and inline comments.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Granular Sharing Controls$q$, $q$Files and folders can be shared with specific people, restricted to link access, or kept private, with viewer, commenter or editor permission levels.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Drive for Desktop$q$, $q$Syncs or streams Drive contents to a local file system on Windows and macOS, including selective offline access.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Shared Drives$q$, $q$Team-owned storage spaces that persist regardless of individual membership changes, aimed at business and organizational use.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Version History$q$, $q$Tracks and allows restoration of prior versions of any file stored in Drive.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Drive API and Marketplace$q$, $q$Lets developers build integrations and third-party apps that read, write and manage files programmatically.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Cross-Platform Access$q$, $q$Native apps for Windows, macOS, iOS and Android plus full web access at drive.google.com.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Enterprise Admin Controls$q$, $q$Workspace administrators get audit logging, data loss prevention rules and domain-wide sharing restrictions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Generous 15GB free storage tier bundled with every Google Account.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Deep native integration with Google Docs, Sheets and Slides for real-time collaboration.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Broad cross-platform support with strong mobile and desktop sync clients.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Shared Drives give teams persistent, centrally managed storage independent of individual membership.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Free and entry-level paid storage is pooled across Gmail, Photos and Drive rather than dedicated solely to files.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Google's 2026 restructuring of storage plans around AI features has made consumer plan naming and pricing more confusing.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Enterprise governance features are generally viewed as less mature than Microsoft's OneDrive and SharePoint stack.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Large file uploads and syncs can be slower than some dedicated sync-focused competitors.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$How much free storage does Google Drive offer?$q$, $q$Every Google Account includes 15GB of free storage shared across Gmail, Drive and Google Photos.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$How much does Google Drive cost beyond the free tier?$q$, $q$Additional personal storage is sold through Google One, starting at $1.99 per month for 100GB and $9.99 per month for 2TB, with annual billing offering a discount.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Can multiple people edit the same file at once in Google Drive?$q$, $q$Yes, Google Docs, Sheets, Slides and Forms support real-time collaborative editing with visible cursors and inline comments for multiple simultaneous editors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$What is the difference between My Drive and Shared Drives?$q$, $q$My Drive is personal storage tied to an individual account, while Shared Drives are team-owned storage spaces available on Google Workspace plans that persist even when members leave the team.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Does Google Drive work offline?$q$, $q$Yes, Drive for desktop and the mobile apps support offline access to selected files, which sync automatically once a connection is restored.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$How does Google Drive compare to Dropbox and OneDrive?$q$, $q$Google Drive differentiates itself through native real-time collaboration in Docs, Sheets and Slides and a larger free storage tier, while OneDrive integrates more deeply with Microsoft Office and Dropbox focuses more narrowly on file sync across platforms.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Personal File Backup and Sharing$q$, $q$Individuals use the free 15GB tier to back up photos, documents and files and share them selectively with family or friends.$q$, $q$Individual consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Team Document Collaboration$q$, $q$Businesses use Shared Drives and real-time collaborative editing to manage team documents, spreadsheets and presentations in one place.$q$, $q$Small business and enterprise teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Education and Classroom File Management$q$, $q$Students and educators use Drive as the default storage layer for assignments, course materials and collaborative classroom projects via Google Classroom.$q$, $q$Students and educators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Free$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["15GB of storage shared across Gmail, Drive and Photos","Real-time collaborative editing in Docs, Sheets and Slides","File sharing with permission controls","Access via web, desktop and mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Google One Basic$q$, $q$$1.99/month$q$, $q$Monthly or annual$q$, NULL, $q$["100GB of pooled storage","Shared across up to 5 family members","Google One member benefits and support","Same collaboration and sharing features as the free tier"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Google One Standard$q$, $q$$9.99/month$q$, $q$Monthly or annual$q$, NULL, $q$["2TB of pooled storage","Shared across up to 5 family members","Bundled AI features such as Gemini in Docs on select regions","Priority Google One member support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$Google Workspace (Business Storage)$q$, $q$Bundled with Workspace plans from $7/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["30GB to 5TB pooled storage per user depending on plan","Shared Drives for team-owned storage","Admin console controls and audit logging","Data loss prevention on higher tiers"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Drive is Google's cloud storage and file synchronization service, launched April 24, 2012, giving every Google Account holder a place to store, sync and share files, including native Google Docs, Sheets and Slides documents alongside any other uploaded file type.$q$, $q$Drive underpins the Google Docs Editors suite and Google Workspace, and it is accessible via a web interface, desktop apps for Windows and macOS, and mobile apps for iOS and Android.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Drive supports real-time collaborative editing in Docs, Sheets and Slides, granular file and folder sharing permissions, offline access through Drive for desktop, and version history for restoring prior file states.$q$, $q$Business users get Shared Drives for team-owned storage that persists independent of individual membership, plus admin console controls, audit logging and data loss prevention when deployed as part of Google Workspace.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Every Google Account includes 15GB of free storage shared across Gmail, Drive and Photos. Additional personal storage is sold through Google One, with a 100GB Basic plan at $1.99 per month and a 2TB Standard plan at $9.99 per month.$q$, $q$Business users get Drive storage bundled into Google Workspace plans rather than purchased separately, with pooled per-user storage ranging from 30GB on Business Starter up to 5TB on Business Plus, and custom allocations on Enterprise plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
