INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bd2fce1d-50cd-44a2-927e-39cfe30406dd', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Multiple Question Types$q$, $q$Supports short answer, paragraph, multiple choice, checkboxes, dropdown, linear scale, grid and file-upload question formats.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Quiz Mode with Auto-Grading$q$, $q$Assigns point values, marks correct answers and auto-grades submissions, integrated with Google Classroom for education use.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Conditional Logic and Branching$q$, $q$Section-based branching sends respondents down different question paths depending on their previous answers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Real-Time Collaborative Editing$q$, $q$Multiple editors can build and revise the same form simultaneously with changes visible instantly to all collaborators.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Live Google Sheets Integration$q$, $q$Responses can be linked live to a Google Sheet for real-time analysis, pivot tables and further automation via Apps Script.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Theme and Visual Customization$q$, $q$Header images, curated color themes and custom fonts let creators match a form's look to their brand or classroom.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Data Validation Rules$q$, $q$Enforces input formats such as numeric ranges or valid email addresses to keep collected data clean.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Forms API and Add-ons$q$, $q$Developers and power users can extend Forms through the API and Google Workspace Marketplace add-ons for notifications, e-signatures and CRM syncing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Completely free with no premium tier or response caps.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Deep native integration with Google Sheets for real-time response analysis.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Built-in Quiz mode with auto-grading is widely used in education via Google Classroom.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Simple, familiar interface accessible to anyone with a free Google Account.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Fewer advanced branching logic and design customization options than dedicated survey tools like Typeform or Jotform.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$No native payment collection for order forms or paid registrations without third-party add-ons.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Visual design options are more limited compared to premium form builders.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Limited built-in analytics compared to research-focused platforms like SurveyMonkey.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Is Google Forms free to use?$q$, $q$Yes, Google Forms is completely free and bundled into every personal Google Account and every tier of Google Workspace, with no premium subscription required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Can Google Forms auto-grade quizzes?$q$, $q$Yes, Forms includes a dedicated Quiz mode that assigns point values, marks correct answers and automatically grades submissions, commonly used with Google Classroom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Do Google Forms responses go into a spreadsheet automatically?$q$, $q$Yes, responses can be linked live to a connected Google Sheet for real-time viewing, analysis and further processing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Can multiple people edit the same Google Form at once?$q$, $q$Yes, Forms supports real-time collaborative editing so multiple users can build or revise a form simultaneously.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Does Google Forms support conditional logic?$q$, $q$Yes, Forms supports section-based branching that routes respondents to different questions depending on their prior answers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$How does Google Forms compare to Typeform or Microsoft Forms?$q$, $q$Google Forms is free and integrates natively with Google Sheets and Classroom, while Typeform offers more advanced design and logic behind a paid subscription, and Microsoft Forms is the closest free equivalent within Microsoft 365.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Classroom Quizzes and Assignments$q$, $q$Teachers build auto-graded quizzes and exit tickets integrated with Google Classroom to assess student understanding.$q$, $q$Educators and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Customer Feedback and Event Registration$q$, $q$Small businesses and event organizers collect customer feedback, order details or RSVP information through simple embeddable forms.$q$, $q$Small businesses and event organizers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Internal Surveys and Data Collection$q$, $q$HR and operations teams use Forms for employee surveys, onboarding intake and internal request forms within organizations already using Google Workspace.$q$, $q$HR and internal operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Google Forms$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Unlimited forms and surveys","Multiple question types and conditional branching","Quiz mode with auto-grading","Real-time Google Sheets response integration","Real-time collaborative form editing","Included with every personal Google Account and Google Workspace plan"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Forms is Google's free online form, survey and quiz builder, introduced in 2008 as part of Google Sheets before becoming a standalone product within the Google Docs Editors suite.$q$, $q$It is bundled into every free Google Account and every Google Workspace subscription, making it one of the most widely distributed form-building tools available, with responses automatically compiled into a connected Google Sheet.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Forms supports multiple question types including multiple choice, checkboxes, dropdowns, linear scale, grids, date and time, and file uploads, with conditional section branching and data validation rules.$q$, $q$A dedicated Quiz mode enables point values, correct-answer marking and automatic grading, integrated directly with Google Classroom, while real-time collaborative editing lets multiple people build a form together simultaneously.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Google Forms is entirely free to use, bundled into every personal Google Account and every tier of Google Workspace, including Education plans, with no separate subscription or usage-based pricing for Forms itself.$q$, $q$There is no premium tier, response cap, or branding-removal fee, which distinguishes it from most dedicated survey and forms competitors that use freemium pricing models.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Native Multimodality$q$, $q$Processes and generates text, images, audio, video and code within a single unified model family rather than separate bolted-on tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Extended Context Window$q$, $q$Supports context windows up to one million tokens on higher-tier plans, enabling analysis of very large documents, codebases or transcripts in one prompt.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Deep Research$q$, $q$Runs multi-step autonomous web research tasks and compiles findings into a structured report.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Workspace Integration$q$, $q$Embedded directly into Gmail, Docs, Sheets and Slides to draft emails, generate formulas, rewrite text and create images and speaker notes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Image and Video Generation$q$, $q$Generates and edits images and video content directly within the Gemini app using Google's generative media models.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Gemini Developer API$q$, $q$Pay-as-you-go API access for developers to integrate Gemini models into their own applications, with enterprise deployment available through Vertex AI.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Cross-Platform Availability$q$, $q$Available via web, dedicated Android and iOS apps, and integration into the Google app and Google Assistant surfaces.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Bundled Google One Storage$q$, $q$Paid Google AI Pro and Ultra subscriptions bundle Google One cloud storage alongside expanded AI usage limits.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Deep native integration across Google's entire product ecosystem, including Search, Gmail and Workspace apps.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Very large context window on paid tiers supports analysis of lengthy documents and codebases.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Native multimodal capability across text, image, audio and video from the ground up.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Free tier provides meaningful access to a capable model without requiring a subscription.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Subscription tier names and pricing have changed frequently, creating confusion for consumers.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Earlier Bard-era output quality issues have affected some users' trust, though later Gemini generations have improved significantly.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Top-tier Google AI Ultra pricing remains high relative to some competing frontier-AI subscriptions.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Some reviewers consider the chat interface less refined for pure conversational use than ChatGPT.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$What is Google Gemini?$q$, $q$Google Gemini is Google's family of multimodal AI models and the consumer chat assistant built on them, developed by Google DeepMind and launched as the rebrand of Google's earlier Bard chatbot in February 2024.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Is Google Gemini free to use?$q$, $q$Yes, Gemini offers a free tier with standard usage limits for any Google Account holder, alongside paid Google AI Plus, Pro and Ultra subscriptions for expanded usage and features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$How much does Google AI Pro (formerly Gemini Advanced) cost?$q$, $q$Google AI Pro is priced at $19.99 per month and includes Google's most capable general-purpose Gemini model, an extended context window, higher usage limits and bundled Google One storage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$What is Google AI Ultra?$q$, $q$Google AI Ultra is Gemini's top consumer tier aimed at power users and developers, offering the highest usage ceilings and priority access to Google's most advanced models, priced at $99.99 per month after a 2026 price reduction from its original $249.99 launch price.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Can developers build with Gemini?$q$, $q$Yes, Google offers a pay-as-you-go Gemini developer API billed per token, along with enterprise deployment options through Google Cloud's Vertex AI platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$How does Gemini compare to ChatGPT and Claude?$q$, $q$Gemini differentiates itself through native multimodality, a very large context window on paid tiers, and deep integration across Google's product ecosystem, while ChatGPT and Claude are frequently rated higher for pure conversational polish by some reviewers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Everyday Writing and Research Assistance$q$, $q$Consumers use the free or Google AI Plus tier for everyday writing help, summarization and general question answering.$q$, $q$Individual consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Productivity Integration in Workspace$q$, $q$Professionals use Gemini embedded in Gmail, Docs, Sheets and Slides to draft content, generate formulas and analyze data without leaving their workflow.$q$, $q$Professionals and Workspace users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Developer and Enterprise AI Integration$q$, $q$Developers and enterprises use the Gemini API and Vertex AI to build custom AI applications and integrate Gemini models into their own products.$q$, $q$Developers and enterprise teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Gemini Free$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Access to a capable Gemini model with standard usage limits","Text, image and basic multimodal chat","Access via web and mobile apps","No payment required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Google AI Plus$q$, $q$$9.99/month$q$, $q$Monthly$q$, NULL, $q$["Expanded usage limits over the free tier","Access to enhanced Gemini features","Priority access during high-demand periods"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Google AI Pro$q$, $q$$19.99/month$q$, $q$Monthly$q$, NULL, $q$["Google's most capable general-purpose Gemini model","Extended context window up to 1 million tokens","Higher compute-based usage limits and monthly AI credits","2TB of Google One storage bundled in"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Google AI Ultra$q$, $q$$99.99/month (reduced from $249.99 after Google I/O 2026)$q$, $q$Monthly$q$, NULL, $q$["Highest usage ceilings for power users","Priority access to Google's most advanced experimental models","Expanded access to Deep Research and video generation tools","Bundled Google One storage"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Gemini is Google's family of multimodal AI models and the consumer chat assistant built on top of them, announced on December 6, 2023, and fully rebranded from Bard on February 8, 2024. It is developed by Google DeepMind, formed in April 2023 from the merger of Google Brain and DeepMind Technologies.$q$, $q$Gemini competes directly with OpenAI's ChatGPT and Anthropic's Claude, and it is deeply integrated across Google's own products, including Search, Gmail, Docs, Sheets, Slides and Android, in addition to being available as a standalone chat app and developer API.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Gemini model family spans multiple tiers optimized for different capability, speed and cost needs, with a context window reaching up to one million tokens on higher-tier plans, allowing very large documents, codebases or video transcripts to be processed in a single prompt.$q$, $q$The consumer app supports natural-language conversation, image generation and editing, document and PDF analysis, code generation, and Deep Research style multi-step web research, while Gemini is also embedded directly into Gmail, Docs, Sheets and Slides.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gemini offers a free tier with standard usage limits, alongside paid Google AI Plus ($9.99/month) and Google AI Pro ($19.99/month, the successor to Gemini Advanced) subscriptions that expand usage limits, unlock the largest context window, and bundle Google One storage.$q$, $q$The top-tier Google AI Ultra plan, aimed at power users and developers, launched at $249.99 per month before being reduced to $99.99 per month following Google's I/O 2026 announcements. A separate pay-as-you-go developer API is billed per token for programmatic use.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Real-Time Collaborative Editing$q$, $q$Docs, Sheets and Slides support simultaneous multi-user editing with live cursors, comments and suggestion mode.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Custom Business Email$q$, $q$Gmail with a custom '@yourcompany.com' domain, spam and phishing protection, and administrative controls.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Google Meet Video Conferencing$q$, $q$Video meetings with participant caps scaling by plan tier, recording, live streaming and noise cancellation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Pooled Cloud Storage$q$, $q$Per-user storage pooled across Gmail and Drive, ranging from 30GB on Business Starter to 5TB on Business Plus.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Admin Console and Security Controls$q$, $q$Centralized user provisioning, two-step verification enforcement, mobile device management and audit logging for IT administrators.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Gemini AI Integration$q$, $q$AI-powered drafting, summarization, formula generation and image creation built directly into Gmail, Docs, Sheets and Slides.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Shared Drives$q$, $q$Team-owned storage spaces that persist independent of individual member changes, with centralized access control.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Shared Calendar and Scheduling$q$, $q$Shared calendars, room and resource booking, and appointment scheduling pages for teams and external clients.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Real-time, browser-native collaborative editing across Docs, Sheets and Slides.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Transparent, predictable per-user pricing tiers compared to some competitor licensing structures.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Gemini AI features are now bundled into Business and Enterprise plans rather than sold as a separate add-on.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Centralized Admin console simplifies IT management for organizations of any size.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Offline functionality is generally considered less mature than native Microsoft Office desktop applications.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Business Starter, Standard and Plus plans cap out at 300 users, forcing larger organizations onto custom Enterprise pricing.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Some enterprise compliance and data governance tooling is viewed as less mature than Microsoft 365's longer-established enterprise IT ecosystem.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Organizations with deep legacy Microsoft Office file format dependencies may encounter compatibility friction.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$What is included in Google Workspace?$q$, $q$Google Workspace includes Gmail with a custom business domain, Google Calendar, Drive, Docs, Sheets, Slides, Meet and Chat, plus an Admin console for centralized IT management and, on Business and Enterprise plans, Gemini AI features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$How much does Google Workspace cost?$q$, $q$Business Starter costs $7 per user per month on annual billing, Business Standard costs $14, and Business Plus costs $22, with flexible monthly billing priced roughly 20 percent higher. Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$What is the difference between Google Workspace and G Suite?$q$, $q$Google Workspace is the current name for the same product previously called G Suite; Google rebranded G Suite as Google Workspace on October 6, 2020, adding tighter cross-app integration.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Is there a user limit on Google Workspace plans?$q$, $q$Business Starter, Standard and Plus plans support up to 300 users per account. Organizations that need more must move to an Enterprise plan, which has no user limit and custom pricing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Does Google Workspace include AI features?$q$, $q$Yes, Gemini AI is integrated into Gmail, Docs, Sheets and Slides across all Business and Enterprise Workspace plans as of 2026, providing drafting, summarization, formula generation and image creation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$How does Google Workspace compare to Microsoft 365?$q$, $q$Google Workspace offers browser-native real-time collaboration and simpler pricing tiers, while Microsoft 365 generally offers more mature offline editing and deeper enterprise compliance tooling for organizations already standardized on Windows.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Small Business Productivity and Email$q$, $q$Small businesses and freelancers use Business Starter for custom email, basic storage and collaborative document editing.$q$, $q$Small businesses and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Mid-Size Team Collaboration$q$, $q$Growing companies use Business Standard or Plus for larger storage pools, bigger video meetings and enhanced security as their teams scale.$q$, $q$Small to mid-sized business teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Enterprise-Wide Deployment$q$, $q$Large organizations deploy custom Enterprise agreements for unlimited users, advanced compliance, eDiscovery and dedicated support.$q$, $q$Enterprise IT and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Business Starter$q$, $q$$7/user/month annual ($8.40/user/month flexible)$q$, $q$Monthly or annual$q$, NULL, $q$["Custom business email with 30GB pooled storage per user","Google Meet video calls for up to 100 participants","Security and management controls","Up to 300 users"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Business Standard$q$, $q$$14/user/month annual ($16.80/user/month flexible)$q$, $q$Monthly or annual$q$, NULL, $q$["2TB pooled storage per user","Google Meet calls for up to 150 participants with recording","Shared Drives for team storage","Up to 300 users"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Business Plus$q$, $q$$22/user/month annual ($26.40/user/month flexible)$q$, $q$Monthly or annual$q$, NULL, $q$["5TB pooled storage per user","Google Meet calls for up to 500 participants","Enhanced security, eDiscovery and retention","Up to 300 users"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom, annual contract$q$, NULL, $q$["No user limit","Advanced security, compliance and eDiscovery","Highest storage allocations","Dedicated support and custom onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Workspace is Google's subscription bundle of cloud productivity tools, including Gmail, Calendar, Drive, Docs, Sheets, Slides, Meet and Chat. It traces back to Gmail for Your Domain in February 2006, was rebranded G Suite in September 2016, and became Google Workspace on October 6, 2020.$q$, $q$Workspace is sold in tiered business plans plus Enterprise and Education variants, and it competes directly with Microsoft 365 as one of the two dominant cloud productivity suites used by organizations worldwide.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Workspace centers on real-time collaborative editing across Docs, Sheets and Slides, custom business email through Gmail, shared scheduling through Calendar, and video conferencing through Meet with participant caps that scale by plan.$q$, $q$The Admin console gives IT teams centralized user provisioning, security enforcement, mobile device management and audit logging, while Gemini AI is now integrated directly into Gmail, Docs, Sheets and Slides across all Business and Enterprise plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Business Starter costs $7/user/month annually ($8.40 monthly) with 30GB pooled storage and 100-participant Meet calls. Business Standard costs $14/user/month annually ($16.80 monthly) with 2TB pooled storage and 150-participant Meet calls.$q$, $q$Business Plus costs $22/user/month annually ($26.40 monthly) with 5TB pooled storage and 500-participant Meet calls. All three Business tiers cap out at 300 users; organizations beyond that move to a custom-quoted Enterprise plan with no user limit.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebc7be94-6513-4a4f-9f90-be0618f1b431', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Terminal-First File Upload$q$, $q$Uploads files directly from the command line using the gpldr client or generic tools like curl, httpie and wget.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Server-Side Encryption$q$, $q$Encrypts uploaded files on the server so raw content is never stored in plaintext on disk.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Self-Hosted Deployment$q$, $q$Runs entirely on infrastructure the user controls, with no third-party cloud dependency.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Docker Support$q$, $q$Ships a published Docker image for quick server deployment with a single docker run command and a persistent data volume.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Basic Web Interface$q$, $q$Includes a simple browser-based interface for users who prefer not to use the command line.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Pre-Built Binaries$q$, $q$Offers ready-to-run binaries for multiple platforms via GitHub Releases, avoiding the need for a local Go installation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Shareable Short Links$q$, $q$Generates unique, shareable URLs for each uploaded file for quick distribution.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$MIT-Licensed Open Source Code$q$, $q$Fully open source under the MIT License, allowing free use, modification and redistribution including commercial use.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Completely free and open source with no subscription or usage fees.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Terminal-first design integrates naturally into scripts, CI pipelines and command-line workflows.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Self-hosted architecture gives full control over data storage and retention.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Small, auditable codebase that a single developer can fully review and understand.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Requires self-hosting and basic systems administration knowledge; there is no managed cloud version.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Maintained by a small volunteer community rather than a commercial team, so support and update cadence are informal.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$The project's own documentation notes parts of the technology stack are comparatively dated.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Smaller feature set and ecosystem compared to full-scale commercial cloud storage or file-sharing platforms.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Is goploader free to use?$q$, $q$Yes, goploader is fully open source under the MIT License and free to use, self-host, modify and redistribute, including for commercial purposes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$What is goploader used for?$q$, $q$goploader is used to quickly and securely share files from the command line, generating a short shareable URL for each upload, commonly for developer workflows, CI pipelines and self-hosted file sharing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Does goploader work with curl or wget?$q$, $q$Yes, because uploads are handled through a simple HTTP API, files can be uploaded directly using curl, httpie or wget in addition to the dedicated gpldr client.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$How do I install goploader?$q$, $q$You can build goploader from source using the Go toolchain, run the server via its published Docker image, or download pre-built binaries from the project's GitHub Releases page.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Who maintains goploader?$q$, $q$goploader is maintained by its original creator, GitHub user Depado, along with a small number of outside contributors, as a volunteer open source project rather than a commercial company.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Is goploader secure?$q$, $q$goploader encrypts uploaded files server-side so raw content is not stored in plaintext, though as a small volunteer-maintained project it does not carry a formal security support SLA.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Command-Line File Sharing$q$, $q$Developers and sysadmins upload build artifacts, logs or screenshots directly from a terminal session without switching to a browser.$q$, $q$Developers and system administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$CI/CD Pipeline Integration$q$, $q$Teams integrate goploader's simple HTTP API into shell scripts and CI/CD pipelines to automatically share generated files.$q$, $q$DevOps and CI/CD engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Privacy-Focused Self-Hosted Sharing$q$, $q$Privacy-conscious individuals and small teams self-host goploader to retain full control over where shared files are stored rather than trusting a third-party service.$q$, $q$Privacy-conscious individuals and small teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Full source code under the MIT License","Client and server binaries for self-hosting","Docker image for quick deployment","Server-side encryption of uploaded files","No usage limits, subscription or fees"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$goploader is a free, open source file-sharing application written in Go, created by developer Depado and inspired by the self-hosted pastebin tool 0bin. It consists of a client binary called gpldr and a server component, with its first stable release, v1.0, shipping on February 9, 2021.$q$, $q$Unlike 0bin's browser-based client-side encryption, goploader performs encryption server-side, which keeps the client simple and lets it work directly with generic command-line HTTP tools such as curl, httpie and wget in addition to its own dedicated client.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core workflow lets users upload a file from the terminal and receive back a short, shareable URL, with the server encrypting stored content so files are not kept in plaintext on disk. A basic web interface is also included for browsing uploads through a browser.$q$, $q$goploader can be installed by building from source with the Go toolchain, running the server via a published Docker image, or downloading pre-built binaries from the project's GitHub Releases page, making self-hosting straightforward across platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$goploader is released under the permissive MIT License and is entirely free to use, modify and redistribute, including for commercial purposes, with no subscription or usage-based fees of any kind.$q$, $q$The only cost to running goploader is the infrastructure a user chooses to host it on, since there is no vendor-managed hosted version and no company selling it as a commercial product.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ffae92bf-f4f5-40c4-b5cb-88cc30edd135', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Unified Omnichannel Inbox$q$, $q$Combines email, live chat, Instagram, Facebook, voice and SMS conversations into a single shared agent workspace.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$AI Support Agent$q$, $q$Automatically resolves common post-purchase questions such as order tracking, returns and refunds using live store data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$AI Shopping Assistant$q$, $q$Engages pre-purchase site visitors with product recommendations and discounts to help convert browsing into sales.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Deep Shopify Integration$q$, $q$Official Shopify Premier Partner integration giving agents and the AI Agent real-time access to orders, inventory and customer tags.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Ticket-Based Pricing$q$, $q$Plans are priced by billable ticket volume rather than number of agent seats, keeping cost the same regardless of team size.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Multilingual AI Responses$q$, $q$The AI Agent replies in more than 80 languages, even when a merchant's own knowledge base exists in only one language.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Vision-Enabled Support$q$, $q$The AI Agent can interpret images customers share, such as photos of damaged items or receipt screenshots.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Action-Taking Automation$q$, $q$Connects to more than 100 ecommerce tools to take direct actions like issuing refunds or updating shipping details, not just answer questions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Deep, real-time Shopify integration purpose-built for ecommerce support workflows.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$AI Agent handles both support resolution and pre-purchase sales assistance in one platform.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Ticket-based pricing keeps costs stable regardless of how many agents are on the team.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Supports replies in over 80 languages even without a translated knowledge base.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Separate AI resolution billing on top of the base plan can make total costs less predictable at high volume.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Deepest integration and value are focused on Shopify, with somewhat less native depth on other ecommerce platforms.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Overage charges for exceeding a plan's billable ticket allotment can add up for fast-growing stores.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Less suited to non-ecommerce industries or complex B2B support workflows compared to general-purpose helpdesks like Zendesk.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$What is Gorgias used for?$q$, $q$Gorgias is used as a customer service helpdesk and AI Agent platform for ecommerce brands, unifying email, chat, social, voice and SMS support with direct access to order and customer data.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$How much does Gorgias cost?$q$, $q$Gorgias plans start at 10 dollars per month for the Starter tier with 50 billable tickets, ranging up to 900 dollars per month for the Advanced tier with 2,000 tickets on monthly billing, with annual billing offering lower rates, plus a custom-quoted Enterprise plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Does Gorgias integrate with Shopify?$q$, $q$Yes, Gorgias is an official Shopify Premier Partner for customer experience with deep, real-time integration into Shopify order data, inventory, product catalogs and customer tags.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Is Gorgias's AI Agent included in every plan?$q$, $q$Yes, the AI Agent is included on every Gorgias plan, though AI conversation resolutions are billed separately based on successful outcomes rather than bundled unlimited into the base subscription price.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Who founded Gorgias?$q$, $q$Gorgias was founded in 2015 by Romain Lapeyre and Alex Plugaru and is headquartered in San Francisco, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$How is Gorgias priced compared to competitors like Zendesk?$q$, $q$Gorgias prices plans based on billable ticket volume rather than the number of agent seats, meaning the subscription cost stays the same regardless of team size, unlike many competitors that charge per agent.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Ecommerce Customer Support$q$, $q$Online retailers use Gorgias to manage high volumes of order-related support conversations across email, chat and social channels in one workspace.$q$, $q$Ecommerce and DTC brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$AI-Automated Support Resolution$q$, $q$Growing brands use the AI Support Agent to automatically resolve routine post-purchase questions like order tracking and returns without human agent involvement.$q$, $q$Customer experience teams at scaling ecommerce brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Conversational Sales Assistance$q$, $q$Merchants use the AI Shopping Assistant to engage pre-purchase site visitors with personalized product recommendations and discounts.$q$, $q$Ecommerce marketing and sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Starter$q$, $q$$10/month$q$, $q$Monthly$q$, NULL, $q$["50 billable tickets per month","AI Agent included","Unified email and chat inbox","$0.40 per additional ticket overage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Basic$q$, $q$$60/month ($50/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["300 billable tickets per month","AI Agent included","Omnichannel support across email, chat and social","Overage billed per additional 100 tickets"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Pro$q$, $q$$360/month ($300/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["2,000 billable tickets per month","AI Agent and Shopping Assistant included","Advanced automation and reporting","Overage billed per additional 100 tickets"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Advanced$q$, $q$$900/month ($750/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Higher billable ticket allotment","Priority support","Advanced automation and workflow tooling","Overage billed per additional 100 tickets"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Enterprise$q$, $q$Custom$q$, $q$Custom, annual contract$q$, NULL, $q$["Custom ticket volume","Advanced security and compliance","Dedicated support and onboarding","Custom contract terms"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gorgias is a customer service helpdesk and AI Agent platform purpose-built for ecommerce, founded in 2015 by Romain Lapeyre and Alex Plugaru and headquartered in San Francisco, California. It unifies email, live chat, social media, voice and SMS support into one agent workspace with direct access to order and customer data.$q$, $q$The company has raised over 100 million dollars in venture funding, including a 30 million dollar Series C in August 2022 led by Transpose Platform and Shopify that valued Gorgias at roughly 710 million dollars, reflecting its especially close relationship with Shopify as an official Premier Partner for customer experience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gorgias centers on a unified inbox spanning email, chat, social, voice and SMS, layered with an AI Agent that handles both post-purchase support questions and pre-purchase shopping assistance, drawing on live Shopify data, help center content and order history to generate accurate, on-brand responses.$q$, $q$The AI Agent can take direct action across more than 100 connected ecommerce tools, such as issuing refunds or editing subscriptions, supports replies in over 80 languages, and includes a vision capability for interpreting customer-submitted images like damaged-item photos.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gorgias prices plans by billable ticket volume rather than number of agent seats, with Starter at 10 dollars per month for 50 tickets, Basic from 50 to 60 dollars per month for 300 tickets, Pro from 300 to 360 dollars per month for 2,000 tickets, and Advanced from 750 to 900 dollars per month, all with annual-billing discounts.$q$, $q$An Enterprise plan is available on a custom quote for high-volume merchants. The AI Agent is included on every plan, but AI resolutions are billed separately based on successful conversation outcomes, and optional Voice and SMS channels carry additional usage-based pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Tablet and Handheld POS$q$, $q$Integrates order-taking, kitchen routing and payment processing in one interface for servers and bartenders.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Mobile QR Ordering and Payment$q$, $q$Guests scan a code to browse a menu, place orders and pay directly from their phone without waiting for a server.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Easy Tab$q$, $q$Lets guests open a tab via card and mobile number capture, then order, reorder and pay from their phone anywhere within the venue.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Self-Ordering Kiosks$q$, $q$Stationary touchscreen kiosks for browsing, ordering and paying via card or contactless mobile wallet, ideal for reducing queue times.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Unified Tab Management$q$, $q$Consolidates all orders from any channel onto a single tab that travels with the guest and settles with one payment.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Multi-Vendor Marketplace$q$, $q$Connects multiple vendors or concepts operating within one venue under a single ordering and payment system.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Cross-Location Reporting$q$, $q$Sales, labor and guest behavior analytics spanning multiple revenue centers and locations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Contactless Payment Support$q$, $q$Accepts credit and debit cards plus mobile wallets such as Apple Pay and Google Wallet across all ordering channels.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Easy Tab feature lets guest tabs travel across a venue's bar, table and patio areas rather than being tied to one location.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Combines traditional staff-operated POS with self-service kiosk and mobile ordering in one unified system.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Well suited to multi-vendor venues like food halls and stadiums that need one system spanning several concepts.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Backed by institutional funding, including a Truist Ventures-led Series A, supporting continued product development.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Pricing is not published and requires contacting sales for a customized quote, making upfront cost comparison harder.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Smaller company size and funding relative to larger competitors like Toast means a smaller integration and partner ecosystem.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Less brand recognition outside the hospitality and entertainment venue industry.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Best-fit use cases lean toward bars, breweries and multi-zone venues, which may mean less specialization for simple single-counter quick-service restaurants.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$What is GoTab used for?$q$, $q$GoTab is used as a restaurant commerce platform combining point of sale, mobile QR ordering, self-service kiosks and portable tab management for restaurants, bars, breweries, hotels and entertainment venues.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$How much does GoTab cost?$q$, $q$GoTab does not publish fixed pricing. It offers Basic and Pro tiers with pricing and setup fees customized per venue, available by contacting a GoTab account executive for a quote.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$What is GoTab's Easy Tab feature?$q$, $q$Easy Tab lets a server open a tab by capturing a guest's card and mobile number, after which the guest can order, reorder and pay from their phone anywhere within the venue until they close out.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Who founded GoTab and where is it headquartered?$q$, $q$GoTab was founded in 2016 by Tim McLaughlin and is headquartered in Arlington, Virginia.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Does GoTab support self-service kiosks?$q$, $q$Yes, GoTab offers self-ordering kiosks that let guests browse, order and pay via card or contactless mobile wallet, with orders routed to the kitchen and guests alerted by text when ready.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$How does GoTab compare to Toast or Square for Restaurants?$q$, $q$GoTab differentiates itself through its Easy Tab model built around portable, guest-controlled tabs that travel across a venue, making it especially well suited to bars, breweries and multi-zone venues, while Toast and Square have larger market share and broader restaurant-industry brand recognition.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Bar and Brewery Tab Management$q$, $q$Bars and breweries use Easy Tab to let guests open a tab, move between the bar and tables, and settle everything with one payment.$q$, $q$Bar and brewery operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Food Hall and Multi-Vendor Venues$q$, $q$Food halls and multi-concept venues use GoTab's Marketplace tools to run several vendors under one unified ordering and payment system.$q$, $q$Food hall and multi-vendor venue operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$High-Volume Stadium and Arena Concessions$q$, $q$Stadiums and arenas deploy self-ordering kiosks and mobile ordering to reduce queue times and speed up concessions during peak demand.$q$, $q$Stadium and entertainment venue operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Basic$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Core POS and mobile ordering functionality","Positioned for small-scale and independent restaurants, bars and breweries","Contactless payment support","Custom setup fee based on venue needs"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$Pro$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Full product suite including kiosks and Easy Tab","Positioned for larger or multi-location hospitality operations","Multi-vendor Marketplace and cross-location reporting","Custom setup fee based on venue needs"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GoTab is a restaurant commerce platform founded in 2016 by Tim McLaughlin and headquartered in Arlington, Virginia, combining point of sale, mobile QR ordering, self-service kiosks and portable tab management for restaurants, bars, breweries, hotels, food halls and stadiums.$q$, $q$The company has raised roughly 24.1 million dollars in venture funding, including a 6 million dollar seed round in 2020, a 3.5 million dollar round in 2021, and an 18 million dollar Series A led by Truist Ventures in 2023, the largest round in its history at the time.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GoTab's core products include a tablet and handheld POS for staff, mobile QR ordering and payment for guests, self-service kiosks for quick-service and high-volume environments, and the Easy Tab feature that lets guests open, reorder and pay a tab from their phone anywhere within a venue.$q$, $q$Every order a guest places, regardless of channel or staff member, consolidates onto a single tab that can travel with them as they move around a venue and be settled with one payment, alongside multi-vendor Marketplace tools and cross-location reporting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GoTab offers two named pricing tiers, Basic for small-scale and independent venues and Pro for larger or multi-location operations, but does not publish fixed per-location rates.$q$, $q$Prospective customers must contact a GoTab account executive for a customized quote and setup estimate, since hardware needs, payment volume and integration complexity vary significantly between venues.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a57ea53a-5e59-4850-be73-20f61d1184e1', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
